"""Провайдер извлечения изображений: конвертация в PNG с ограничением размера."""from __future__ import annotationsimport threadingfrom pathlib import Pathfrom src.modules.file_discovery.models import DiscoveredDocumentfrom ...interfaces import FileExtractProviderfrom ...services.file_extract_cache import FileExtractCacheServicefrom ...services.image_processing_service import (    write_normalized_from_file,)from ...models import (    CONTENT_TYPE_IMAGE,    ExtractConfig,    ExtractedDocument,    ExtractedDocumentContent,    SEMANTIC_TYPE_REQUIRED_DETECTION,    SourceDocument,)from src.modules.settings_schema.models import SettingFieldSchemaIMAGE_ALGORITHM_SKIP = "skip"IMAGE_ALGORITHM_PROCESS = "process"class ImageExtractProvider(FileExtractProvider):    """Извлечение для графических форматов: конвертирует в PNG с ограничением размера."""    PROVIDER_CODE: str = "image_extract_provider"    PROVIDER_TITLE: str = "Обработка изображений"    PAGE_IMAGE_FORMAT: str = "jpg"    DEFAULT_MAX_SIZE: int = 1200    @staticmethod    def supported_extensions() -> set[str]:        return {".png", ".jpg", ".jpeg", ".webp", ".bmp", ".gif", ".tif", ".tiff", ".svg"}    @classmethod    def project_settings_schema(cls) -> tuple[SettingFieldSchema, ...]:        return (            SettingFieldSchema(                key="algorithm",                type="select",                default=IMAGE_ALGORITHM_PROCESS,                label="Алгоритм работы",                description="Простой загрузчик, если указаны модели обработки изображений, система попытается определить текст на изображениях. Векторные изображения (svg) растрируются по размеру изображений ниже",                options=(                    (IMAGE_ALGORITHM_SKIP, "Пропустить"),                    (IMAGE_ALGORITHM_PROCESS, "Распознать содержимое"),                ),            ),            SettingFieldSchema(                key="max_size",                type="int",                default=cls.DEFAULT_MAX_SIZE,                label="Размер изображений",                description="Если изображение будет больше указанного, оно будет уменьшено пропорционально. Чем изображение больше, тем лучше качество распознования, но и обработка стоит дороже",            ),        )    def _normalize_params(self, config: ExtractConfig) -> int:        raw_max_size = self.get_setting(config, "max_size", self.DEFAULT_MAX_SIZE)        try:            max_size = int(raw_max_size)        except (TypeError, ValueError):            max_size = self.DEFAULT_MAX_SIZE        return max(1, max_size)    def extract(        self,        source: SourceDocument,        config: ExtractConfig,        storage: FileExtractCacheService,        document_hash: str,        cancel_event: threading.Event | None = None,    ) -> ExtractedDocument:        if cancel_event is not None and cancel_event.is_set():            return ExtractedDocument(                source=DiscoveredDocument(                    path=str(source.path),                    folder=source.folder,                    filename=source.filename,                    extension=source.normalized_extension(),                    mime_type=source.mime_type,                    hash=source.file_hash,                ),                config=config,                extract_hash=document_hash,                content=[],            )        algorithm = (self.get_setting(config, "algorithm") or IMAGE_ALGORITHM_PROCESS).strip().lower()        if algorithm == IMAGE_ALGORITHM_SKIP:            return ExtractedDocument(                source=DiscoveredDocument(                    path=str(source.path),                    folder=source.folder,                    filename=source.filename,                    extension=source.normalized_extension(),                    mime_type=source.mime_type,                    hash=source.file_hash,                ),                config=config,                extract_hash=document_hash,                content=[],            )        content: list[ExtractedDocumentContent] = []        if cancel_event is None or not cancel_event.is_set():            stem = Path(source.filename).stem or "image"            source_path = source.path_obj()            max_size = self._normalize_params(config)            def _write_converted(path: Path) -> None:                write_normalized_from_file(                    source_path,                    path,                    self.PAGE_IMAGE_FORMAT,                    max_size,                    source_ext=source.normalized_extension(),                )            item = storage.save_generated_file_content(                filename=f"{stem}.jpg",                writer=_write_converted,                content_type=CONTENT_TYPE_IMAGE,                semantic_type=SEMANTIC_TYPE_REQUIRED_DETECTION,            )            content.append(item)        return ExtractedDocument(            source=DiscoveredDocument(                path=str(source.path),                folder=source.folder,                filename=source.filename,                extension=source.normalized_extension(),                mime_type=source.mime_type,                hash=source.file_hash,            ),            config=config,            extract_hash=document_hash,            content=content,        )